<template><div class="workspace-page"><section class="page-intro"><div><p>非健康内容管理</p><h2>账号管理</h2><span>普通用户支持停用、恢复和不可逆级联删除；机构账号删除后历史报告保留账号名快照。</span></div></section><el-card shadow="never"><div class="filter-row"><el-input v-model="keyword" placeholder="搜索用户名、邮箱或手机号" clearable/><el-select v-model="role"><el-option label="全部角色" value=""/><el-option label="普通用户" value="user"/><el-option label="机构账号" value="institution_admin"/><el-option label="管理员" value="admin"/></el-select></div><el-table :data="filtered" v-loading="loading"><el-table-column prop="username" label="账号"/><el-table-column label="角色"><template #default="s"><el-tag>{{roleName(s.row.role)}}</el-tag></template></el-table-column><el-table-column label="机构"><template #default="s">{{s.row.managed_institution?.name||'-'}}</template></el-table-column><el-table-column label="状态"><template #default="s"><el-tag :type="s.row.is_active?'success':'info'">{{s.row.is_active?'启用':'停用'}}</el-tag></template></el-table-column><el-table-column width="220"><template #default="s"><template v-if="s.row.role==='user'"><el-button link @click="toggle(s.row)">{{s.row.is_active?'停用':'恢复'}}</el-button><el-button link type="danger" @click="remove(s.row)">级联删除</el-button></template><el-button v-else-if="s.row.role==='institution_admin'" link type="danger" @click="removeStaff(s.row)">删除机构账号</el-button></template></el-table-column></el-table></el-card></div></template><script setup>import{computed,onMounted,ref}from"vue";import{ElMessage,ElMessageBox}from"element-plus";import{deleteInstitutionAccount}from"../../api/admin";import{deleteUser,fetchUsers,updateUser}from"../../api/users";const items=ref([]),loading=ref(false),keyword=ref(""),role=ref("");const roleName=r=>({user:"普通用户",institution_admin:"机构账号",admin:"系统管理员"}[r]||r);const filtered=computed(()=>items.value.filter(i=>(!role.value||i.role===role.value)&&`${i.username} ${i.email||''} ${i.phone||''}`.toLowerCase().includes(keyword.value.toLowerCase())));async function load(){loading.value=true;try{items.value=(await fetchUsers()).data.items||[]}finally{loading.value=false}}async function toggle(i){await updateUser(i.id,{is_active:!i.is_active});await load()}async function remove(i){try{await ElMessageBox.confirm(`将永久删除 ${i.username} 及其资料、测量、登记、已匹配报告、亲友关系和评论，无法恢复。`,`确认级联删除`,{type:"error",confirmButtonText:"永久删除"});await deleteUser(i.id);ElMessage.success("用户已完整删除");await load()}catch(e){if(e!=="cancel"&&e!=="close")ElMessage.error(e?.response?.data?.message||"删除失败")}}async function removeStaff(i){try{await ElMessageBox.confirm("仅删除登录账号，历史报告和提交用户名快照会保留。","删除机构账号",{type:"warning"});await deleteInstitutionAccount(i.id);await load()}catch(e){if(e!=="cancel"&&e!=="close")ElMessage.error("删除失败")}}onMounted(load);</script>
